import React from "react";

const LoginBox = () => {
  return (
    <div className="flex flex-col items-center w-full">
      <h2 className="text-xl font-semibold text-gray-800 mb-4">Login</h2>

      {/* Email Input */}
      <input
        type="email"
        placeholder="Email"
        className="w-full p-2 mb-3 border border-gray-300 rounded text-gray-900"
      />

      {/* Password Input */}
      <input
        type="password"
        placeholder="Password"
        className="w-full p-2 mb-4 border border-gray-300 rounded text-gray-900"
      />

      {/* Login Button */}
      <button className="bg-blue-600 text-white px-4 py-2 rounded-lg w-full hover:bg-blue-700 transition">
        Login
      </button>
    </div>
  );
};

export default LoginBox;
